import{E as t}from"./index-YJU_NjKJ.js";const p={getList(e){return t.get("/problems",{params:e})},getDetail(e){return t.get(`/problems/${e}`)},submit(e,r){return t.post(`/problems/${e}/submit`,r)},debug(e,r){return t.post(`/problems/${e}/debug`,r)},getDebugResult(e){return t.get(`/problems/debug/result/${e}`)},create(e){return t.post("/problems",e)},update(e,r){return t.put(`/problems/${e}`,r)},delete(e){return t.delete(`/problems/${e}`)}};export{p};
